// Decisions.jsx
import React, { useMemo, useState } from "react";

/*
  Decisions.jsx
  - Single-file React component for the "Replacement Decisions" page
  - Renders ONLY page content (AdminLayout provides header/sidebar/footer)
  - Tailwind CSS for styling
  - Dummy JSON data included below (replace with ML Decision / Financial APIs in production)

  Integration notes (placeholders):
  - Backend ML API should provide replacement requests with fields:
      {
        id,                    // system id or request id
        systemId,
        owner,                 // owner / department
        requestedBy,           // user who requested replacement
        aiVerdict,             // 'approve' | 'reject' (ML final recommendation)
        rootCause,             // 'Hardware' | 'Software' | 'Security'
        confidence,            // number 0-100
        estimatedCost,         // number (currency)
        riskIfDelayed,         // 'Low' | 'Medium' | 'High'
        status,                // 'pending' | 'approved' | 'rejected' | 'deferred'
        timestamps: {          // audit timestamps
          requestedAt, aiVerdictAt, reviewedAt, finalDecisionAt
        },
        systemSnapshot: {      // small summary returned by system API / ML pipeline
          ageYears, warrantyUntil, healthTrend // array of points or simple summary text
        },
        evidence: {
          hardware: [...],
          software: [...],
          security: [...]
        },
        financial: {
          downtimeCostPerHour,
          repairEstimate,
          replaceEstimate
        },
        timeline: [ { ts, actor, action, note } ]
      }
  - View Decision -> opens drawer with details (client-side only)
  - Approve / Reject / Defer / Request More Evidence -> call review APIs (placeholders)
  - Sorting / Filtering -> ideally performed server-side via query params; here we do client-side for demo
*/

const DUMMY_REQUESTS = [
  {
    id: "REQ-2026-001",
    systemId: "SYS-8472",
    owner: "Manufacturing / Line B",
    requestedBy: "tech.alex",
    aiVerdict: "approve",
    rootCause: "Hardware",
    confidence: 94,
    estimatedCost: 4200,
    riskIfDelayed: "High",
    status: "pending",
    timestamps: {
      requestedAt: new Date(Date.now() - 48 * 60 * 60 * 1000).toISOString(), // 48h ago
      aiVerdictAt: new Date(Date.now() - 36 * 60 * 60 * 1000).toISOString(),
      reviewedAt: null,
      finalDecisionAt: null,
    },
    systemSnapshot: {
      ageYears: 4,
      warrantyUntil: new Date(Date.now() + 60 * 24 * 60 * 60 * 1000).toISOString(),
      healthTrend: [
        { label: "30d", value: 78 },
        { label: "14d", value: 62 },
        { label: "7d", value: 55 },
        { label: "1d", value: 42 },
      ],
    },
    evidence: {
      hardware: [
        "SMART warnings: reallocated sectors rising",
        "I/O latencies correlated with backup windows",
      ],
      software: ["Backup job overlapping causing higher I/O"],
      security: ["No persistent malicious indicators"],
    },
    financial: {
      downtimeCostPerHour: 1200,
      repairEstimate: 1800,
      replaceEstimate: 4200,
    },
    timeline: [
      { ts: new Date(Date.now() - 48 * 60 * 60 * 1000).toISOString(), actor: "tech.alex", action: "Requested replacement", note: "Intermittent failures observed" },
      { ts: new Date(Date.now() - 36 * 60 * 60 * 1000).toISOString(), actor: "ML Engine", action: "AI verdict", note: "Recommend APPROVE (94% confidence)" },
    ],
  },

  {
    id: "REQ-2026-002",
    systemId: "SYS-9031",
    owner: "Data Center / Rack 7",
    requestedBy: "ops.maya",
    aiVerdict: "reject",
    rootCause: "Software",
    confidence: 78,
    estimatedCost: 1600,
    riskIfDelayed: "Medium",
    status: "pending",
    timestamps: {
      requestedAt: new Date(Date.now() - 10 * 60 * 60 * 1000).toISOString(),
      aiVerdictAt: new Date(Date.now() - 9 * 60 * 60 * 1000).toISOString(),
      reviewedAt: null,
      finalDecisionAt: null,
    },
    systemSnapshot: {
      ageYears: 2,
      warrantyUntil: null,
      healthTrend: [
        { label: "30d", value: 88 },
        { label: "7d", value: 84 },
        { label: "1d", value: 80 },
      ],
    },
    evidence: {
      hardware: ["No hardware anomalies"],
      software: ["Misconfigured service causing retries", "Patch pending"],
      security: ["No issues"],
    },
    financial: {
      downtimeCostPerHour: 400,
      repairEstimate: 400,
      replaceEstimate: 1600,
    },
    timeline: [
      { ts: new Date(Date.now() - 10 * 60 * 60 * 1000).toISOString(), actor: "ops.maya", action: "Requested replacement", note: "App-level restarts observed" },
      { ts: new Date(Date.now() - 9 * 60 * 60 * 1000).toISOString(), actor: "ML Engine", action: "AI verdict", note: "Recommend REJECT (78% confidence)" },
    ],
  },

  {
    id: "REQ-2026-003",
    systemId: "SYS-7720",
    owner: "R&D / Lab",
    requestedBy: "eng.sam",
    aiVerdict: "approve",
    rootCause: "Hardware",
    confidence: 85,
    estimatedCost: 1200,
    riskIfDelayed: "Low",
    status: "approved",
    timestamps: {
      requestedAt: new Date(Date.now() - 6 * 24 * 60 * 60 * 1000).toISOString(),
      aiVerdictAt: new Date(Date.now() - 5.5 * 24 * 60 * 60 * 1000).toISOString(),
      reviewedAt: new Date(Date.now() - 4 * 24 * 60 * 60 * 1000).toISOString(),
      finalDecisionAt: new Date(Date.now() - 3.5 * 24 * 60 * 60 * 1000).toISOString(),
    },
    systemSnapshot: {
      ageYears: 5,
      warrantyUntil: null,
      healthTrend: [
        { label: "90d", value: 85 },
        { label: "30d", value: 70 },
        { label: "7d", value: 48 },
      ],
    },
    evidence: {
      hardware: ["Repeated ECC corrections on memory", "SMART critical thresholds exceeded"],
      software: ["N/A"],
      security: ["N/A"],
    },
    financial: {
      downtimeCostPerHour: 200,
      repairEstimate: 200,
      replaceEstimate: 1200,
    },
    timeline: [
      { ts: new Date(Date.now() - 6 * 24 * 60 * 60 * 1000).toISOString(), actor: "eng.sam", action: "Requested replacement", note: "Frequent crashes during tests" },
      { ts: new Date(Date.now() - 5.5 * 24 * 60 * 60 * 1000).toISOString(), actor: "ML Engine", action: "AI verdict", note: "Recommend APPROVE (85% confidence)" },
      { ts: new Date(Date.now() - 4 * 24 * 60 * 60 * 1000).toISOString(), actor: "lead.jordan", action: "Approved replacement", note: "Order placed" },
    ],
  },
];

// ---------- Utilities ----------
function currency(v) {
  return v.toLocaleString(undefined, { style: "currency", currency: "USD", maximumFractionDigits: 0 });
}

function relativeTime(iso) {
  const d = Math.floor((Date.now() - new Date(iso).getTime()) / 1000);
  if (d < 60) return `${d}s ago`;
  if (d < 3600) return `${Math.floor(d / 60)}m ago`;
  if (d < 86400) return `${Math.floor(d / 3600)}h ago`;
  return `${Math.floor(d / 86400)}d ago`;
}

function statusBadgeClass(status) {
  switch (status) {
    case "pending":
      return "bg-yellow-50 text-yellow-800";
    case "approved":
      return "bg-green-50 text-green-800";
    case "rejected":
      return "bg-red-50 text-red-800";
    case "deferred":
      return "bg-slate-50 text-slate-800";
    default:
      return "bg-gray-100 text-gray-800";
  }
}

function riskBadgeClass(risk) {
  if (risk === "High") return "bg-red-50 text-red-700";
  if (risk === "Medium") return "bg-yellow-50 text-yellow-800";
  return "bg-green-50 text-green-700";
}

// ---------- Component ----------
export default function Decisions() {
  const [requests, setRequests] = useState(DUMMY_REQUESTS);
  const [query, setQuery] = useState("");
  const [statusFilter, setStatusFilter] = useState("All");
  const [rootCauseFilter, setRootCauseFilter] = useState("All");
  const [sortKey, setSortKey] = useState("timestamps.requestedAt"); // default sort
  const [sortDir, setSortDir] = useState("desc");

  // Drawer state
  const [drawerOpen, setDrawerOpen] = useState(false);
  const [selected, setSelected] = useState(null);

  // Action reason input within drawer
  const [actionMode, setActionMode] = useState(null); // 'approve' | 'reject' | 'defer' | 'evidence'
  const [actionReason, setActionReason] = useState("");

  // Search + filters
  const visible = useMemo(() => {
    const q = query.trim().toLowerCase();
    const filtered = requests.filter((r) => {
      if (statusFilter !== "All" && r.status !== statusFilter.toLowerCase()) return false;
      if (rootCauseFilter !== "All" && r.rootCause !== rootCauseFilter) return false;
      if (!q) return true;
      return (
        r.id.toLowerCase().includes(q) ||
        r.systemId.toLowerCase().includes(q) ||
        r.owner.toLowerCase().includes(q) ||
        r.requestedBy.toLowerCase().includes(q)
      );
    });

    // basic sorting
    const sorted = [...filtered].sort((a, b) => {
      const get = (obj, path) => path.split(".").reduce((s, k) => (s ? s[k] : undefined), obj);
      const va = get(a, sortKey);
      const vb = get(b, sortKey);
      if (va == null && vb == null) return 0;
      if (va == null) return sortDir === "asc" ? -1 : 1;
      if (vb == null) return sortDir === "asc" ? 1 : -1;
      if (typeof va === "number" && typeof vb === "number") return sortDir === "asc" ? va - vb : vb - va;
      return sortDir === "asc" ? String(va).localeCompare(String(vb)) : String(vb).localeCompare(String(va));
    });

    return sorted;
  }, [requests, query, statusFilter, rootCauseFilter, sortKey, sortDir]);

  // KPI badges
  const kpis = useMemo(() => {
    const pending = requests.filter((r) => r.status === "pending").length;
    const approvedToday = requests.filter((r) => {
      if (!r.timestamps.finalDecisionAt) return false;
      const d = new Date(r.timestamps.finalDecisionAt);
      const now = new Date();
      return d.toDateString() === now.toDateString() && r.status === "approved";
    }).length;
    const costAtRisk = requests
      .filter((r) => r.status === "pending")
      .reduce((s, r) => s + (r.estimatedCost || 0), 0);
    return { pending, approvedToday, costAtRisk };
  }, [requests]);

  // Open drawer for item
  const openDrawer = (req) => {
    setSelected(req);
    setActionMode(null);
    setActionReason("");
    setDrawerOpen(true);
  };

  // Close drawer
  const closeDrawer = () => {
    setDrawerOpen(false);
    setSelected(null);
    setActionMode(null);
    setActionReason("");
  };

  // Perform action (placeholder - should call backend review API)
  const performAction = (mode) => {
    if (!selected) return;
    if (!actionReason || actionReason.trim().length < 5) {
      alert("Please provide a reason (min 5 characters) for this action.");
      return;
    }

    // Placeholder: update local state to simulate review action
    setRequests((prev) =>
      prev.map((r) =>
        r.id === selected.id
          ? {
              ...r,
              status:
                mode === "approve" ? "approved" : mode === "reject" ? "rejected" : mode === "defer" ? "deferred" : r.status,
              timestamps: {
                ...r.timestamps,
                reviewedAt: new Date().toISOString(),
                finalDecisionAt: mode === "approve" || mode === "reject" ? new Date().toISOString() : r.timestamps.finalDecisionAt,
              },
              timeline: [
                ...r.timeline,
                { ts: new Date().toISOString(), actor: "reviewer.current", action: mode === "approve" ? "Approved" : mode === "reject" ? "Rejected" : mode === "defer" ? "Deferred" : "Requested more evidence", note: actionReason },
              ],
            }
          : r
      )
    );

    // Log to console as a placeholder for backend call
    console.log(`Action performed: ${mode} on ${selected.id} with reason: `, actionReason);

    // Close drawer after action
    closeDrawer();
  };

  // Sorting helper
  const toggleSort = (key) => {
    if (sortKey === key) {
      setSortDir((d) => (d === "asc" ? "desc" : "asc"));
    } else {
      setSortKey(key);
      setSortDir("desc");
    }
  };

  // Executive insights derived from dummy data (client-side)
  const insights = useMemo(() => {
    const moneySaved = requests.filter((r) => r.status === "rejected").reduce((s, r) => s + (r.estimatedCost || 0), 0);
    const falseClaims = requests.filter((r) => r.status === "rejected" && r.aiVerdict === "approve").length;
    const agingTrend = Math.round(requests.reduce((s, r) => s + (r.systemSnapshot?.ageYears || 0), 0) / requests.length);
    return { moneySaved, falseClaims, agingTrend };
  }, [requests]);

  return (
    <div className="p-6 bg-gray-50 min-h-[calc(100vh-4rem)]">
      {/* Header */}
      <div className="flex flex-col md:flex-row md:items-center md:justify-between gap-4 mb-6">
        <div>
          <h1 className="text-2xl font-semibold text-slate-900">Replacement Decisions</h1>
          <p className="text-sm text-slate-600">AI-verified hardware replacement approvals</p>
        </div>

        <div className="flex items-center gap-3">
          {/* KPI badges */}
          <div className="flex gap-2">
            <div className="px-3 py-2 bg-white border rounded-md text-sm">
              <div className="text-xs text-slate-500">Pending Requests</div>
              <div className="font-semibold">{kpis.pending}</div>
            </div>
            <div className="px-3 py-2 bg-white border rounded-md text-sm">
              <div className="text-xs text-slate-500">Approved Today</div>
              <div className="font-semibold">{kpis.approvedToday}</div>
            </div>
            <div className="px-3 py-2 bg-white border rounded-md text-sm">
              <div className="text-xs text-slate-500">Cost at Risk</div>
              <div className="font-semibold">{currency(kpis.costAtRisk)}</div>
            </div>
          </div>
        </div>
      </div>

      {/* Controls: Search / Filters / Sort */}
      <div className="mb-4 flex flex-col sm:flex-row sm:items-center sm:justify-between gap-3">
        <div className="flex items-center gap-2 w-full sm:w-auto">
          <input
            placeholder="Search by request, system, owner, or requester"
            value={query}
            onChange={(e) => setQuery(e.target.value)}
            className="px-3 py-2 border rounded-md w-full sm:w-96 bg-white"
            aria-label="Search replacement requests"
          />
          <button onClick={() => { setQuery(""); }} className="px-3 py-2 bg-slate-100 rounded-md text-sm">Clear</button>
        </div>

        <div className="flex items-center gap-2">
          <select value={statusFilter} onChange={(e) => setStatusFilter(e.target.value)} className="px-3 py-2 border rounded-md bg-white text-sm">
            <option>All</option>
            <option>pending</option>
            <option>approved</option>
            <option>rejected</option>
            <option>deferred</option>
          </select>

          <select value={rootCauseFilter} onChange={(e) => setRootCauseFilter(e.target.value)} className="px-3 py-2 border rounded-md bg-white text-sm">
            <option>All</option>
            <option>Hardware</option>
            <option>Software</option>
            <option>Security</option>
          </select>

          <div className="flex items-center gap-2 text-sm">
            <button onClick={() => toggleSort("confidence")} className="px-3 py-2 border rounded-md bg-white">Sort: Confidence</button>
            <button onClick={() => toggleSort("estimatedCost")} className="px-3 py-2 border rounded-md bg-white">Sort: Cost</button>
            <button onClick={() => toggleSort("timestamps.requestedAt")} className="px-3 py-2 border rounded-md bg-white">Sort: Requested</button>
          </div>
        </div>
      </div>

      {/* Main: Replacement Queue Table */}
      <div className="bg-white border rounded-lg shadow overflow-auto">
        <table className="min-w-full divide-y">
          <thead className="bg-gray-50 sticky top-0">
            <tr className="text-xs text-gray-600 uppercase">
              <th className="px-4 py-3 text-left">Request ID</th>
              <th className="px-4 py-3 text-left">System ID</th>
              <th className="px-4 py-3 text-left">Owner</th>
              <th className="px-4 py-3 text-left">Requested By</th>
              <th className="px-4 py-3 text-left">AI Verdict</th>
              <th className="px-4 py-3 text-left">Root Cause</th>
              <th className="px-4 py-3 text-right">Confidence</th>
              <th className="px-4 py-3 text-right">Est. Cost</th>
              <th className="px-4 py-3 text-left">Risk if Delayed</th>
              <th className="px-4 py-3 text-left">Status</th>
              <th className="px-4 py-3 text-left">Action</th>
            </tr>
          </thead>

          <tbody className="bg-white divide-y">
            {visible.length === 0 ? (
              <tr>
                <td colSpan={11} className="p-8 text-center text-sm text-slate-500">
                  No replacement requests found. Adjust filters or search.
                </td>
              </tr>
            ) : (
              visible.map((r) => (
                <tr key={r.id} className="hover:bg-gray-50">
                  <td className="px-4 py-3 text-sm text-sky-600 font-medium">
                    <button onClick={() => openDrawer(r)} className="hover:underline">{r.id}</button>
                  </td>
                  <td className="px-4 py-3 text-sm">{r.systemId}</td>
                  <td className="px-4 py-3 text-sm">{r.owner}</td>
                  <td className="px-4 py-3 text-sm">{r.requestedBy}</td>
                  <td className="px-4 py-3 text-sm capitalize">
                    <span className={`px-2 py-1 rounded-full text-xs ${r.aiVerdict === "approve" ? "bg-green-50 text-green-700" : "bg-red-50 text-red-700"}`}>
                      {r.aiVerdict}
                    </span>
                  </td>
                  <td className="px-4 py-3 text-sm">{r.rootCause}</td>
                  <td className="px-4 py-3 text-right text-sm">{r.confidence}%</td>
                  <td className="px-4 py-3 text-right text-sm">{currency(r.estimatedCost)}</td>
                  <td className="px-4 py-3 text-sm">
                    <span className={`px-2 py-1 rounded-full text-xs ${riskBadgeClass(r.riskIfDelayed)}`}>{r.riskIfDelayed}</span>
                  </td>
                  <td className="px-4 py-3 text-sm">
                    <span className={`px-2 py-1 rounded-full text-xs ${statusBadgeClass(r.status)}`}>{r.status}</span>
                  </td>
                  <td className="px-4 py-3 text-sm">
                    <div className="flex gap-2">
                      <button onClick={() => openDrawer(r)} className="px-2 py-1 border rounded-md text-sm hover:bg-slate-50">View Decision</button>
                      <button
                        onClick={() => {
                          // Quick approve (UI-only) - in real app prompt for reason via modal
                          openDrawer(r);
                          setTimeout(() => { setActionMode("approve"); }, 50);
                        }}
                        className="px-2 py-1 bg-green-600 text-white rounded-md text-sm hover:bg-green-700"
                        title="Quick open and approve (requires reason)"
                      >
                        Quick Action
                      </button>
                    </div>
                  </td>
                </tr>
              ))
            )}
          </tbody>
        </table>
      </div>

      {/* Executive Insights */}
      <div className="mt-6 grid grid-cols-1 sm:grid-cols-3 gap-4">
        <div className="bg-white border rounded-md p-4">
          <div className="text-xs text-slate-500">Money Saved (Rejected requests)</div>
          <div className="text-xl font-semibold mt-2">{currency(insights.moneySaved)}</div>
          <div className="text-sm text-slate-500 mt-1">Estimated savings by avoiding unnecessary replacements</div>
        </div>

        <div className="bg-white border rounded-md p-4">
          <div className="text-xs text-slate-500">False Claims Detected</div>
          <div className="text-xl font-semibold mt-2">{insights.falseClaims}</div>
          <div className="text-sm text-slate-500 mt-1">Requests where AI recommended approve but reviewers rejected</div>
        </div>

        <div className="bg-white border rounded-md p-4">
          <div className="text-xs text-slate-500">Hardware Aging (Avg years)</div>
          <div className="text-xl font-semibold mt-2">{insights.agingTrend} years</div>
          <div className="text-sm text-slate-500 mt-1">Average system age for requests in queue</div>
        </div>
      </div>

      {/* Decision Drawer (right sliding panel) */}
      {drawerOpen && selected && (
        <div className="fixed inset-0 z-50 flex">
          {/* Overlay */}
          <div className="absolute inset-0 bg-black/30" onClick={closeDrawer} />

          <aside className="ml-auto w-full sm:w-[780px] bg-white shadow-xl overflow-y-auto">
            <div className="p-5 border-b flex items-start justify-between">
              <div>
                <div className="text-xs text-slate-500">Decision Detail</div>
                <div className="text-lg font-semibold">{selected.id} — {selected.systemId}</div>
                <div className="text-sm text-slate-600">Requested by {selected.requestedBy} · {relativeTime(selected.timestamps.requestedAt)}</div>
              </div>
              <div>
                <button onClick={closeDrawer} className="px-3 py-1 text-sm rounded-md bg-slate-100">Close</button>
              </div>
            </div>

            <div className="p-5 space-y-6">
              {/* A. System Snapshot */}
              <section className="grid grid-cols-1 md:grid-cols-3 gap-4">
                <div className="md:col-span-2 bg-gray-50 p-4 rounded-md">
                  <div className="text-sm text-slate-500">System Snapshot</div>
                  <div className="mt-2 text-sm text-slate-700">
                    <div><strong>System:</strong> {selected.systemId}</div>
                    <div><strong>Age:</strong> {selected.systemSnapshot?.ageYears ?? "—"} years</div>
                    <div><strong>Warranty until:</strong> {selected.systemSnapshot?.warrantyUntil ? new Date(selected.systemSnapshot.warrantyUntil).toLocaleDateString() : "Expired / N/A"}</div>
                    <div className="mt-2 text-sm text-slate-500">Health Trend (summary): {selected.systemSnapshot?.healthTrend?.map(h => `${h.label}:${h.value}`).join(" • ")}</div>
                  </div>
                </div>

                <div className="bg-white p-4 rounded-md border">
                  <div className="text-sm text-slate-500">AI Decision Verdict</div>
                  <div className="mt-2 flex items-center gap-3">
                    <div className={`px-3 py-1 rounded-full text-sm ${selected.aiVerdict === "approve" ? "bg-green-50 text-green-700" : "bg-red-50 text-red-700"}`}>{selected.aiVerdict.toUpperCase()}</div>
                    <div className="text-sm text-slate-600">Confidence: <span className="font-medium">{selected.confidence}%</span></div>
                  </div>
                  <div className="mt-3 text-sm text-slate-600">
                    {/* Explanation is synthesized from evidence in real system. */}
                    {selected.aiVerdict === "approve" ? "AI recommends replacement due to strong hardware failure signals and historical patterns." : "AI recommends rejecting replacement; software or configuration likely cause."}
                  </div>
                </div>
              </section>

              {/* B. Evidence Summary */}
              <section>
                <div className="text-sm font-semibold text-slate-800 mb-2">Evidence Summary</div>
                <div className="grid grid-cols-1 md:grid-cols-3 gap-3">
                  <div className="bg-white border rounded-md p-3">
                    <div className="text-xs text-slate-500">Hardware Evidence</div>
                    <ul className="mt-2 text-sm text-slate-600 space-y-1">
                      {(selected.evidence.hardware || []).map((e, i) => <li key={i}>• {e}</li>)}
                    </ul>
                  </div>
                  <div className="bg-white border rounded-md p-3">
                    <div className="text-xs text-slate-500">Software Evidence</div>
                    <ul className="mt-2 text-sm text-slate-600 space-y-1">
                      {(selected.evidence.software || []).map((e, i) => <li key={i}>• {e}</li>)}
                    </ul>
                  </div>
                  <div className="bg-white border rounded-md p-3">
                    <div className="text-xs text-slate-500">Security Evidence</div>
                    <ul className="mt-2 text-sm text-slate-600 space-y-1">
                      {(selected.evidence.security || []).map((e, i) => <li key={i}>• {e}</li>)}
                    </ul>
                  </div>
                </div>
              </section>

              {/* C. Financial Impact */}
              <section className="bg-gray-50 border rounded-md p-4">
                <div className="text-sm font-semibold text-slate-800">Financial Impact</div>
                <div className="mt-2 grid grid-cols-1 md:grid-cols-3 gap-3">
                  <div>
                    <div className="text-xs text-slate-500">Replacement Cost</div>
                    <div className="text-lg font-semibold mt-1">{currency(selected.financial.replaceEstimate || selected.estimatedCost)}</div>
                  </div>
                  <div>
                    <div className="text-xs text-slate-500">Downtime risk / hr</div>
                    <div className="text-lg font-semibold mt-1">{currency(selected.financial.downtimeCostPerHour)}</div>
                  </div>
                  <div>
                    <div className="text-xs text-slate-500">Repair vs Replace</div>
                    <div className="text-sm mt-1 text-slate-600">
                      Repair: {currency(selected.financial.repairEstimate)} • Replace: {currency(selected.financial.replaceEstimate || selected.estimatedCost)}
                    </div>
                    <div className="text-xs text-slate-500 mt-2">3-year ROI insight: {selected.estimatedCost > (selected.financial.downtimeCostPerHour * 24 * 30) ? "Replace may reduce risk" : "Repair may be cost-effective short-term"}</div>
                  </div>
                </div>
              </section>

              {/* D. Action Buttons + Reason input */}
              <section className="bg-white border rounded-md p-4">
                <div className="flex items-center justify-between">
                  <div>
                    <div className="text-sm font-semibold">Reviewer Actions</div>
                    <div className="text-xs text-slate-500">Select an action and provide rationale (required)</div>
                  </div>
                  <div className="flex gap-2">
                    <button onClick={() => { setActionMode("approve"); setActionReason(""); }} className="px-3 py-2 bg-green-600 text-white rounded-md text-sm">Approve Replacement</button>
                    <button onClick={() => { setActionMode("reject"); setActionReason(""); }} className="px-3 py-2 bg-red-50 text-red-700 rounded-md text-sm border">Reject Request</button>
                    <button onClick={() => { setActionMode("defer"); setActionReason(""); }} className="px-3 py-2 bg-slate-50 text-slate-700 rounded-md text-sm border">Defer Decision</button>
                    <button onClick={() => { setActionMode("evidence"); setActionReason(""); }} className="px-3 py-2 bg-yellow-50 text-yellow-800 rounded-md text-sm border">Request More Evidence</button>
                  </div>
                </div>

                {actionMode && (
                  <div className="mt-4 space-y-2">
                    <div className="text-sm text-slate-600">Action: <span className="font-medium">{actionMode}</span></div>
                    <textarea
                      value={actionReason}
                      onChange={(e) => setActionReason(e.target.value)}
                      placeholder="Enter reason for this decision (required)"
                      className="w-full border rounded-md p-2 min-h-[96px] bg-white"
                    />
                    <div className="flex gap-2 justify-end">
                      <button onClick={() => { setActionMode(null); setActionReason(""); }} className="px-3 py-2 border rounded-md text-sm">Cancel</button>
                      <button onClick={() => performAction(actionMode)} className="px-3 py-2 bg-sky-600 text-white rounded-md text-sm">Submit Decision</button>
                    </div>
                  </div>
                )}
              </section>

              {/* E. Audit Trail */}
              <section>
                <div className="flex items-center justify-between">
                  <div className="text-sm font-semibold">Audit Trail</div>
                  <div className="text-xs text-slate-500">Expand to view timestamps and notes</div>
                </div>
                <div className="mt-3 space-y-2">
                  {selected.timeline.map((t, i) => (
                    <div key={i} className="bg-white border rounded-md p-3">
                      <div className="flex items-start justify-between">
                        <div>
                          <div className="text-sm font-medium">{t.action} · <span className="text-xs text-slate-500">{t.actor}</span></div>
                          <div className="text-xs text-slate-500 mt-1">{t.note}</div>
                        </div>
                        <div className="text-xs text-slate-400">{relativeTime(t.ts)}</div>
                      </div>
                    </div>
                  ))}
                </div>
              </section>
            </div>
          </aside>
        </div>
      )}
    </div>
  );
}
